function test_is_json_encoded_object() {
    $exchange = new \ccxt\async\Exchange(array(
        'id' => 'sampleexchange',
    ));
    assert($exchange->is_json_encoded_object('{"key":"value"}'));
    assert($exchange->is_json_encoded_object('{}'));
    assert($exchange->is_json_encoded_object('[]'));
    // todo: the belows  are not ideal, but currently valid
    assert($exchange->is_json_encoded_object('{x'));
    assert($exchange->is_json_encoded_object('[x'));
    assert($exchange->is_json_encoded_object('{'));
    assert($exchange->is_json_encoded_object('['));
    // invalid
    assert(!$exchange->is_json_encoded_object('x'));
    assert(!$exchange->is_json_encoded_object(''));
    assert(!$exchange->is_json_encoded_object('}'));
    assert(!$exchange->is_json_encoded_object(']'));
    assert(!$exchange->is_json_encoded_object('null'));
    assert(!$exchange->is_json_encoded_object('undefined'));
}
